import type { ConflictInfo } from './types.js';

export interface ConflictResolutionStrategy {
  type: 'automatic' | 'manual' | 'custom';
  preference?: 'local' | 'remote' | 'newer' | 'merge';
  customResolver?: (conflict: ConflictInfo) => any;
}

export interface ConflictResolutionResult {
  resolved: boolean;
  value: any;
  strategy: string;
  confidence: number;
}

/**
 * ConflictResolution handles merge conflicts in collaborative editing
 */
export class ConflictResolution {
  private strategies: Map<string, ConflictResolutionStrategy> = new Map();
  private conflictHistory: ConflictInfo[] = [];

  constructor() {
    this.setupDefaultStrategies();
  }

  /**
   * Register a conflict resolution strategy for a specific path pattern
   */
  registerStrategy(pathPattern: string, strategy: ConflictResolutionStrategy): void {
    this.strategies.set(pathPattern, strategy);
  }

  /**
   * Resolve a conflict based on registered strategies
   */
  resolveConflict(conflict: ConflictInfo): ConflictResolutionResult {
    // Track conflict for analysis
    this.conflictHistory.push(conflict);

    // Try automatic resolution first
    if (conflict.autoResolvable) {
      const autoResult = this.tryAutomaticResolution(conflict);
      if (autoResult.resolved) {
        return autoResult;
      }
    }

    // Find matching strategy
    const strategy = this.findMatchingStrategy(conflict.path);

    if (strategy) {
      return this.applyStrategy(conflict, strategy);
    }

    // Default resolution
    return this.defaultResolution(conflict);
  }

  /**
   * Get conflict history for analysis
   */
  getConflictHistory(): ConflictInfo[] {
    return [...this.conflictHistory];
  }

  /**
   * Clear conflict history
   */
  clearHistory(): void {
    this.conflictHistory = [];
  }

  /**
   * Analyze conflict patterns
   */
  analyzeConflictPatterns(): {
    totalConflicts: number;
    byType: Record<string, number>;
    byPath: Record<string, number>;
    resolutionSuccess: number;
  } {
    const analysis = {
      totalConflicts: this.conflictHistory.length,
      byType: {} as Record<string, number>,
      byPath: {} as Record<string, number>,
      resolutionSuccess: 0
    };

    this.conflictHistory.forEach(conflict => {
      // Count by type
      analysis.byType[conflict.type] = (analysis.byType[conflict.type] || 0) + 1;

      // Count by path
      const pathKey = conflict.path.join('.');
      analysis.byPath[pathKey] = (analysis.byPath[pathKey] || 0) + 1;

      // Count successful resolutions
      if (conflict.autoResolvable) {
        analysis.resolutionSuccess++;
      }
    });

    return analysis;
  }

  /**
   * Set up default resolution strategies
   */
  private setupDefaultStrategies(): void {
    // Timing conflicts - prefer more conservative (longer) timing
    this.registerStrategy('*.duration', {
      type: 'automatic',
      preference: 'merge',
      customResolver: (conflict) => {
        const local = parseFloat(conflict.localValue);
        const remote = parseFloat(conflict.remoteValue);
        return Math.max(local, remote);
      }
    });

    // Position conflicts - prefer local user's positioning
    this.registerStrategy('*.position.*', {
      type: 'automatic',
      preference: 'local'
    });

    // Metadata conflicts - merge objects
    this.registerStrategy('metadata.*', {
      type: 'automatic',
      preference: 'merge',
      customResolver: (conflict) => {
        if (typeof conflict.localValue === 'object' && typeof conflict.remoteValue === 'object') {
          return { ...conflict.remoteValue, ...conflict.localValue };
        }
        return conflict.localValue;
      }
    });

    // Array order conflicts - require manual resolution
    this.registerStrategy('timeline.*.order', {
      type: 'manual'
    });
  }

  /**
   * Try automatic resolution for simple conflicts
   */
  private tryAutomaticResolution(conflict: ConflictInfo): ConflictResolutionResult {
    // Numeric values - average or max
    if (typeof conflict.localValue === 'number' && typeof conflict.remoteValue === 'number') {
      if (conflict.type === 'timing') {
        // For timing, use maximum to be safe
        return {
          resolved: true,
          value: Math.max(conflict.localValue, conflict.remoteValue),
          strategy: 'max-value',
          confidence: 0.9
        };
      } else {
        // For other numbers, average
        return {
          resolved: true,
          value: (conflict.localValue + conflict.remoteValue) / 2,
          strategy: 'average',
          confidence: 0.7
        };
      }
    }

    // String values - check if one is empty
    if (typeof conflict.localValue === 'string' && typeof conflict.remoteValue === 'string') {
      if (!conflict.localValue.trim()) {
        return {
          resolved: true,
          value: conflict.remoteValue,
          strategy: 'non-empty',
          confidence: 0.8
        };
      }
      if (!conflict.remoteValue.trim()) {
        return {
          resolved: true,
          value: conflict.localValue,
          strategy: 'non-empty',
          confidence: 0.8
        };
      }
    }

    // Boolean values - require manual resolution
    if (typeof conflict.localValue === 'boolean' && typeof conflict.remoteValue === 'boolean') {
      if (conflict.localValue !== conflict.remoteValue) {
        return {
          resolved: false,
          value: conflict.localValue,
          strategy: 'manual-required',
          confidence: 0
        };
      }
    }

    return {
      resolved: false,
      value: conflict.localValue,
      strategy: 'no-auto-resolution',
      confidence: 0
    };
  }

  /**
   * Find matching strategy for a path
   */
  private findMatchingStrategy(path: string[]): ConflictResolutionStrategy | null {
    const pathString = path.join('.');

    // Check exact match first
    if (this.strategies.has(pathString)) {
      return this.strategies.get(pathString)!;
    }

    // Check pattern matches
    for (const [pattern, strategy] of this.strategies) {
      if (this.matchesPattern(pathString, pattern)) {
        return strategy;
      }
    }

    return null;
  }

  /**
   * Check if a path matches a pattern
   */
  private matchesPattern(path: string, pattern: string): boolean {
    // Convert pattern to regex
    // First escape dots, then handle ** for any depth, then * for single segment
    const regexPattern = pattern
      .replace(/\./g, '\\.')
      .replace(/\*\*/g, '__DOUBLE_STAR__')
      .replace(/\*/g, '[^.]+')
      .replace(/__DOUBLE_STAR__/g, '.*');

    const regex = new RegExp(`^${regexPattern}$`);
    return regex.test(path);
  }

  /**
   * Apply a resolution strategy
   */
  private applyStrategy(conflict: ConflictInfo, strategy: ConflictResolutionStrategy): ConflictResolutionResult {
    if (strategy.type === 'manual') {
      return {
        resolved: false,
        value: conflict.localValue,
        strategy: 'manual',
        confidence: 0
      };
    }

    if (strategy.customResolver) {
      try {
        const value = strategy.customResolver(conflict);
        return {
          resolved: true,
          value,
          strategy: 'custom',
          confidence: 0.8
        };
      } catch (error) {
        console.error('Custom resolver failed:', error);
      }
    }

    // Apply preference-based resolution
    switch (strategy.preference) {
      case 'local':
        return {
          resolved: true,
          value: conflict.localValue,
          strategy: 'prefer-local',
          confidence: 0.7
        };

      case 'remote':
        return {
          resolved: true,
          value: conflict.remoteValue,
          strategy: 'prefer-remote',
          confidence: 0.7
        };

      case 'newer':
        // This would require timestamp information
        return {
          resolved: true,
          value: conflict.localValue, // Default to local without timestamps
          strategy: 'prefer-newer',
          confidence: 0.5
        };

      case 'merge':
        if (typeof conflict.localValue === 'object' && typeof conflict.remoteValue === 'object') {
          return {
            resolved: true,
            value: this.mergeObjects(conflict.localValue, conflict.remoteValue),
            strategy: 'merge',
            confidence: 0.8
          };
        }
        break;
    }

    return this.defaultResolution(conflict);
  }

  /**
   * Default resolution when no strategy matches
   */
  private defaultResolution(conflict: ConflictInfo): ConflictResolutionResult {
    // Check if this is a boolean conflict that differs
    if (typeof conflict.localValue === 'boolean' && 
        typeof conflict.remoteValue === 'boolean' &&
        conflict.localValue !== conflict.remoteValue) {
      return {
        resolved: false,
        value: conflict.localValue,
        strategy: 'manual-required',
        confidence: 0
      };
    }

    if (conflict.suggestedResolution) {
      const value = conflict.suggestedResolution === 'local' 
        ? conflict.localValue 
        : conflict.suggestedResolution === 'remote'
        ? conflict.remoteValue
        : this.mergeValues(conflict.localValue, conflict.remoteValue);

      return {
        resolved: true,
        value,
        strategy: `suggested-${conflict.suggestedResolution}`,
        confidence: 0.6
      };
    }

    // Default to local value
    return {
      resolved: true,
      value: conflict.localValue,
      strategy: 'default-local',
      confidence: 0.5
    };
  }

  /**
   * Merge two objects recursively
   */
  private mergeObjects(local: any, remote: any): any {
    if (Array.isArray(local) && Array.isArray(remote)) {
      // For arrays, concatenate and remove duplicates
      return [...new Set([...local, ...remote])];
    }

    if (typeof local === 'object' && typeof remote === 'object') {
      const merged: any = { ...remote };

      for (const key in local) {
        if (key in remote) {
          merged[key] = this.mergeValues(local[key], remote[key]);
        } else {
          merged[key] = local[key];
        }
      }

      return merged;
    }

    return local;
  }

  /**
   * Merge two values
   */
  private mergeValues(local: any, remote: any): any {
    if (typeof local === typeof remote) {
      if (typeof local === 'object') {
        return this.mergeObjects(local, remote);
      }
    }
    return local;
  }
}

