import { IndexeddbPersistence } from 'y-indexeddb';
import type { ExperimentCRDT } from './ExperimentCRDT.js';
import type { SyncStatus } from './types.js';

export interface OfflineChange {
  id: string;
  timestamp: number;
  path: string[];
  value: any;
  synced: boolean;
}

export type SyncStatusCallback = (status: SyncStatus) => void;

/**
 * OfflineSync handles offline editing and automatic synchronization
 * when the connection is restored.
 */
export class OfflineSync {
  private persistence: IndexeddbPersistence;
  private pendingChanges: OfflineChange[] = [];
  private syncStatus: SyncStatus = {
    connected: false,
    syncing: false,
    pendingChanges: 0,
    provider: 'offline'
  };
  private statusCallbacks: Set<SyncStatusCallback> = new Set();
  private reconnectTimer: NodeJS.Timeout | null = null;
  private reconnectAttempts = 0;
