    elementId: string;
    elementType: 'timeline' | 'trial' | 'stimulus' | 'code';
  };
  lastActivity: number;
  isActive: boolean;
}

export interface VisualChangeEvent {
  type: 'move' | 'add' | 'delete' | 'update';
  elementId: string;
  elementType: 'trial' | 'stimulus' | 'response';
  position?: {
    timeline?: number;
    trial?: number;
    index?: number;
  };
  oldPosition?: {
    timeline?: number;
    trial?: number;
    index?: number;
  };
  data?: any;
}

export interface CodeChangeEvent {
  type: 'insert' | 'delete' | 'replace';
  range: {
    startLine: number;
    startColumn: number;
    endLine: number;
    endColumn: number;
  };
  text: string;
  source: 'user' | 'sync';
}

export interface ConflictInfo {
  type: 'structural' | 'property' | 'timing';
  path: string[];
  localValue: any;
  remoteValue: any;
  baseValue?: any;
  autoResolvable: boolean;
  suggestedResolution?: 'local' | 'remote' | 'merge';
}

export interface SyncStatus {
  connected: boolean;
  syncing: boolean;
  pendingChanges: number;
  lastSyncTime?: number;
  provider: 'webrtc' | 'websocket' | 'offline';
  error?: string;
}

export interface CollaborationMetrics {
  syncLatency: number;
  changeRate: number;
  conflictRate: number;
  activeUsers: number;
  dataSize: number;
}

// Re-export some types that will be defined in ForgeScript
export interface ForgeScriptAST {
  metadata?: Record<string, any>;
  timeline?: any[];
  conditions?: Record<string, any>;
  stimuli?: any[];
  rawCode?: string;
}

export interface CompiledExperiment {
  id: string;
  name: string;
  metadata: Record<string, any>;
  timeline: any[];
  conditions: Record<string, any>;
  stimuli: any[];
}

// Monaco editor types (simplified for now)
export interface IEditor {
  getValue(): string;
  setValue(value: string): void;
  onDidChangeModelContent(listener: (e: any) => void): { dispose(): void };
  getModel(): any;
  executeEdits(source: string, edits: any[]): void;
}

// Timeline types
export interface ITimeline {
  on(event: string, handler: (e: any) => void): void;
  off(event: string, handler: (e: any) => void): void;
  getElements(): any[];
  updateElement(id: string, data: any): void;
  addElement(type: string, data: any): string;
  removeElement(id: string): void;
}

